INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1718, 198032, 9, 135, '加油', '开赛以来我一直关心咖啡的动向,知道前几场成绩不理想,不过不要气馁,毕竟第一次参加如此大规模的市级联赛,经验不足是难免的,不过大家重在参与,享受足球的快乐是最重要的~,咖啡里面大部分是纯粹的业余选手,比起其他企业队毫无优势可言,但重要的是大家都是为了自己所热爱的运动聚在一起,也都热爱着这个集体,这个大家庭,前面的失利不要放心上,认真打好后面的比赛就行,放开包袱,放开手脚踢出自己的风格来~加油了~!!!', '开赛以来我一直关心咖啡的动向,知道前几场成绩不理想,不过不要气馁,毕竟第一次参加如此大规模的市级联赛,经验不足是难免的,不过大家重在参与,享受足球的快乐是最重要的~,咖啡里面大部分是纯粹的业余选手,比起其他企业队毫无优势可言,但重要的是大家都是为了自己所热爱的运动聚在一起,也都热爱着这个集体,这个大家庭,前面的失利不要放心上,认真打好后面的比赛就行,放开包袱,放开手脚踢出自己的风格来~加油了~!!!', NULL, '2003-03-10 14:22:00', 8, '20030425044104_bbsid_198032_board_9_501b3ab2a9.html', '20030425044104');
